// Tinos font (Times New Roman compatible) — embedded for offline pdfmake use
(function() {
  if (typeof pdfMake === 'undefined') return;
  pdfMake.vfs['Tinos-Regular.ttf'] = '';
  pdfMake.vfs['Tinos-Italic.ttf']  = '';
  pdfMake.fonts = pdfMake.fonts || {};
  pdfMake.fonts['Tinos'] = {
    normal:  'Tinos-Regular.ttf',
    italics: 'Tinos-Italic.ttf',
    bold:    'Tinos-Regular.ttf',
    bolditalics: 'Tinos-Italic.ttf'
  };
})();